// FEHD catalogue: load + search. The "基本盤" — a complete HK restaurant list.
import type { Catalogue, Restaurant } from "./types";

let cache: Catalogue | null = null;

export async function loadCatalogue(baseUrl: string): Promise<Catalogue> {
  if (cache) return cache;
  const res = await fetch(`${baseUrl}data/restaurants.json`);
  if (!res.ok) throw new Error(`catalogue load failed: ${res.status}`);
  cache = (await res.json()) as Catalogue;
  return cache;
}

function norm(s: string): string {
  return (s || "").toLowerCase().replace(/[\s'()（）.,·&-]/g, "");
}

export function searchRestaurants(
  cat: Catalogue,
  query: string,
  limit = 20
): Restaurant[] {
  const q = norm(query);
  if (!q) return [];
  const out: Restaurant[] = [];
  for (const r of cat.restaurants) {
    if (norm(r.name.tc).includes(q) || norm(r.name.en).includes(q)) {
      out.push(r);
      if (out.length >= limit) break;
    }
  }
  return out;
}

/** First restaurant whose name contains `name` — used to resolve mock memories
 *  to REAL catalogue entries so seeded data points at real places. */
export function findByName(cat: Catalogue, name: string): Restaurant | null {
  const q = norm(name);
  if (!q) return null;
  return (
    cat.restaurants.find(
      (r) => norm(r.name.tc).includes(q) || norm(r.name.en).includes(q)
    ) ?? null
  );
}

export function byId(cat: Catalogue, id: string): Restaurant | null {
  return cat.restaurants.find((r) => r.id === id) ?? null;
}

export interface CatFilter {
  region?: string; // HK / KLN / NT
  type?: string; // RL / RR / MR
}

/** Browse the full catalogue by optional text + region/type filters. Returns
 *  the first `limit` matches plus the total match count (for "N 間" display). */
export function browseRestaurants(
  cat: Catalogue,
  query: string,
  filter: CatFilter,
  limit = 20
): { items: Restaurant[]; total: number } {
  const q = norm(query);
  const items: Restaurant[] = [];
  let total = 0;
  for (const r of cat.restaurants) {
    if (filter.region && r.region !== filter.region) continue;
    if (filter.type && r.type !== filter.type) continue;
    if (q && !(norm(r.name.tc).includes(q) || norm(r.name.en).includes(q))) continue;
    total += 1;
    if (items.length < limit) items.push(r);
  }
  return { items, total };
}
